function syncChainData(
    uint64 _chainId,
    bytes32 _kind,
    uint64 _blockId,
    bytes32 _chainData
)
    external
    returns (bytes32)
{
    if (!isAuthorized[msg.sender]) revert SS_UNAUTHORIZED();
    return _syncChainData(_chainId, _kind, _blockId, _chainData);
}

